#include <iostream>
using namespace std;

int main() {
  int S = 43;
  int j = 3;

  cout << ( S & ( 1 << j ) ) << endl;

  return 0;
}

// Teniendo en cuenta que cada operación
// influye en la siguiente:

S      = 011010 (bin) = 26 (dec)
S << 1 = 110100 (bin) = 52 (dec) = S * 2
S >> 2 = 001101 (bin) = 13 (dec) = S / 2²
S >> 1 = 011010 (bin) = 6  (dec) = S / 2

